import React, { useEffect, useRef, useState } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

const VideoCall = ({ roomId, userId, onLeave }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [stats, setStats] = useState(null);
  
  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const remoteVideosRef = useRef(new Map());

  // In VideoCall.js, add canvas capture
const captureFrame = () => {
  const canvas = document.createElement('canvas');
  canvas.width = 640;
  canvas.height = 480;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(localVideoRef.current, 0, 0, 640, 480);
  return canvas.toDataURL('image/jpeg', 0.8);
};


  useEffect(() => {
    // Connect to signaling server
    socketRef.current = io('http://localhost:3001', {
      transports: ['websocket'],
      upgrade: false
    });

    const aiSocket = new WebSocket('ws://localhost:8080'); // Change port to your AI server port

    aiSocket.onopen = () => {
    console.log('Connected to AI processing server');
    // Store in ref for access elsewhere
    aiSocketRef.current = aiSocket;
  };
  
  aiSocket.onmessage = async (event) => {
    // Receive processed frame from AI server
    const processedData = await event.data;
    
    // ===== ADD LATENCY MEASUREMENT HERE =====
    const latency = performance.now() - lastFrameSendTime.current;
    console.log(`AI processing latency: ${latency.toFixed(2)}ms`);
    
    // Update stats for display
    setAiLatency(latency);
    
    // Here you would display the processed frame
    // For now, just log it
    console.log('Received processed frame:', processedData);
  };
  
  aiSocket.onerror = (error) => {
    console.error('AI WebSocket error:', error);
  };
  
  aiSocket.onclose = () => {
    console.log('Disconnected from AI server');
  };

    // Get user media
    navigator.mediaDevices.getUserMedia({ 
      video: { 
        width: { ideal: 640 },
        height: { ideal: 480 },
        frameRate: { ideal: 30 }
      }, 
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }
    })
      .then(stream => {
        setLocalStream(stream);
        if (localVideoRef.current) {
          localVideoRef.current.srcObject = stream;
        }

        // Join room after getting stream
        socketRef.current.emit('join-room', { roomId, userId });

        setConnectionStatus('connected');
      })
      .catch(error => {
        console.error('Error accessing media devices:', error);
        setConnectionStatus('error');
      });

    // Socket event handlers
    socketRef.current.on('room-joined', ({ participants, isHost }) => {
      console.log('Joined room, participants:', participants);
      // Create peer connections for existing participants
      participants.forEach(participant => {
        createPeer(participant.socketId, true);
      });
    });

    socketRef.current.on('user-connected', ({ userId, socketId }) => {
      console.log('User connected:', userId, socketId);
      createPeer(socketId, false);
    });

    socketRef.current.on('offer', ({ offer, from }) => {
      console.log('Received offer from:', from);
      createPeer(from, false, offer);
    });

    socketRef.current.on('answer', ({ answer, from }) => {
      console.log('Received answer from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(answer);
      }
    });

    socketRef.current.on('ice-candidate', ({ candidate, from }) => {
      console.log('Received ICE candidate from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(candidate);
      }
    });

    socketRef.current.on('user-disconnected', ({ socketId, userId }) => {
      console.log('User disconnected:', userId);
      // Remove peer
      const peer = peersRef.current.find(p => p.peerID === socketId);
      if (peer) {
        peer.peer.destroy();
      }
      peersRef.current = peersRef.current.filter(p => p.peerID !== socketId);
      
      // Remove remote video
      const videoElement = remoteVideosRef.current.get(socketId);
      if (videoElement) {
        videoElement.srcObject = null;
        videoElement.remove();
        remoteVideosRef.current.delete(socketId);
      }

      setPeers(peersRef.current.map(p => p.peerID));
    });

    socketRef.current.on('error', ({ message }) => {
      console.error('Socket error:', message);
      setConnectionStatus('error');
    });

    return () => {
      // Cleanup
      if (localStream) {
        localStream.getTracks().forEach(track => track.stop());
      }
      
      peersRef.current.forEach(peer => {
        peer.peer.destroy();
      });
      
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId]);

  const createPeer = (targetSocketId, initiator, offer = null) => {
    if (!localStream) return;

    const peer = new Peer({
      initiator: initiator,
      stream: localStream,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' },
          { urls: 'stun:stun2.l.google.com:19302' }
        ]
      }
    });

    // Add to peers ref
    peersRef.current.push({
      peerID: targetSocketId,
      peer: peer
    });

    setPeers(peersRef.current.map(p => p.peerID));

    // Handle signaling
    peer.on('signal', signal => {
      if (initiator && !offer) {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (offer) {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    // Handle stream
    peer.on('stream', stream => {
      console.log('Received stream from peer:', targetSocketId);
      
      // Create or get video element
      let videoElement = remoteVideosRef.current.get(targetSocketId);
      if (!videoElement) {
        videoElement = document.createElement('video');
        videoElement.id = `remote-video-${targetSocketId}`;
        videoElement.autoplay = true;
        videoElement.playsInline = true;
        remoteVideosRef.current.set(targetSocketId, videoElement);
      }
      
      videoElement.srcObject = stream;
      setRemoteStreams(new Map(remoteVideosRef.current));
    });

    peer.on('connect', () => {
      console.log('Peer connection established with:', targetSocketId);
    });

    peer.on('error', err => {
      console.error('Peer error:', err);
    });

    peer.on('close', () => {
      console.log('Peer connection closed with:', targetSocketId);
    });

    // If offer was provided, signal it
    if (offer) {
      peer.signal(offer);
    }
  };

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(track => {
        track.enabled = !isAudioEnabled;
      });
      setIsAudioEnabled(!isAudioEnabled);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(track => {
        track.enabled = !isVideoEnabled;
      });
      setIsVideoEnabled(!isVideoEnabled);
    }
  };

  const getConnectionStatusColor = () => {
    switch(connectionStatus) {
      case 'connected': return 'bg-green-500';
      case 'connecting': return 'bg-yellow-500';
      case 'error': return 'bg-red-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="space-y-4">
      {/* Connection Status */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className={`h-3 w-3 rounded-full ${getConnectionStatusColor()}`}></div>
            <span className="text-sm font-medium text-gray-700">
              Room: {roomId} | Users in call: {peers.length + 1}
            </span>
          </div>
          <button
            onClick={onLeave}
            className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600 transition text-sm"
          >
            Leave Call
          </button>
        </div>
      </div>

      {/* Video Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Local Video */}
        <div className="bg-black rounded-lg overflow-hidden relative">
          <video
            ref={localVideoRef}
            autoPlay
            playsInline
            muted
            className="w-full h-full object-cover"
          />
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
            You {!isVideoEnabled && '(Video Off)'} {!isAudioEnabled && '(Muted)'}
          </div>
        </div>

        {/* Remote Videos */}
        {Array.from(remoteStreams).map(([socketId, videoElement]) => (
          <div key={socketId} className="bg-black rounded-lg overflow-hidden relative">
            <video
              ref={el => {
                if (el && videoElement && !el.srcObject) {
                  el.srcObject = videoElement.srcObject;
                }
              }}
              autoPlay
              playsInline
              className="w-full h-full object-cover"
            />
            <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
              Peer {socketId.substring(0, 8)}
            </div>
          </div>
        ))}

        {/* Placeholder for empty grid */}
        {peers.length === 0 && (
          <div className="bg-gray-800 rounded-lg p-8 text-center text-gray-400 flex items-center justify-center min-h-[200px]">
            <p>Waiting for others to join...</p>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex justify-center space-x-4">
          <button
            onClick={toggleAudio}
            className={`p-3 rounded-full ${
              isAudioEnabled ? 'bg-blue-500 hover:bg-blue-600' : 'bg-red-500 hover:bg-red-600'
            } text-white transition`}
          >
            {isAudioEnabled ? (
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            ) : (
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2" />
              </svg>
            )}
          </button>

          <button
            onClick={toggleVideo}
            className={`p-3 rounded-full ${
              isVideoEnabled ? 'bg-blue-500 hover:bg-blue-600' : 'bg-red-500 hover:bg-red-600'
            } text-white transition`}
          >
            {isVideoEnabled ? (
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            ) : (
              <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18.364 18.364A9 9 0 005.636 5.636m12.728 12.728A9 9 0 015.636 5.636m12.728 12.728L5.636 5.636" />
              </svg>
            )}
          </button>
        </div>
      </div>

      {/* Stats for debugging */}
      {process.env.NODE_ENV === 'development' && (
        <div className="bg-gray-800 text-green-400 p-4 rounded-lg font-mono text-xs">
          <div>Peers: {peers.length}</div>
          <div>Socket ID: {socketRef.current?.id || 'Not connected'}</div>
          <div>Connection Status: {connectionStatus}</div>
        </div>
      )}
    </div>
  );
};

export default VideoCall;
